package com.establo.controller;import com.establo.dto.UserDto;import com.establo.service.UserService;import jakarta.validation.Valid;import lombok.RequiredArgsConstructor;import org.springframework.security.access.prepost.PreAuthorize;import org.springframework.web.bind.annotation.*;import java.util.List;
@RestController @RequestMapping("/api/users") @RequiredArgsConstructor @PreAuthorize("hasRole('ADMIN')") public class UserController {private final UserService service;@GetMapping List<UserDto> all(){return service.all();}@PatchMapping("/{id}/role") UserDto role(@PathVariable Long id,@Valid @RequestBody UserDto.RoleUpdate d){return service.role(id,d.role());}@PatchMapping("/{id}/status") UserDto status(@PathVariable Long id,@RequestBody UserDto.StatusUpdate d){return service.status(id,d.active());}}
